SELECT SUM(contribution_amount) AS total_contributions
FROM campaign_contributions
WHERE contribution_status = 'approved' AND contribution_cycle = '2022-2024';

SELECT contribution_amount
FROM campaign_contributions
ORDER BY contribution_amount DESC;

SELECT committee_name
FROM committees
ORDER BY committee_name ASC;

SELECT candidate_id, SUM(contribution_amount) AS total_contributions
FROM campaign_contributions
GROUP BY candidate_id;
